hooks.command:
file=$(cat | jq -r '.tool_input.file_path // empty'); if [[ "$file" =~ src/components/([A-Z][^/]+)\.tsx$ ]] && [[ ! "$file" =~ \.stories\.tsx$ ]]; then name="${BASH_REMATCH[1]}"; stories="${file%.tsx}.stories.tsx"; if [ ! -f "$stories" ]; then printf 'import type { Meta, StoryObj } from "@storybook/react";
import %s from "./%s";

const meta: Meta<typeof %s> = {
  component: %s,
};
export default meta;

type Story = StoryObj<typeof %s>;

export const Default: Story = {};
' "$name" "$name" "$name" "$name" "$name" > "$stories"; fi; fi
